+import { getDoorElements, getCorridorElements, getRoomContainer } from './dom_utils';
+import { wait } from './utils';
+
+// Duration constants in ms
+const DOOR_ANIMATION_DURATION = 400;
+const ROOM_FADE_DURATION = 300;
+
+/**
+ * Animate door opening or closing.
+ * @param {HTMLElement} doorEl - The door DOM element.
+ * @param {boolean} open - True to open, false to close.
+ * @returns {Promise<void>}
+ */
+export async function animateDoor(doorEl, open) {
+  if (!doorEl) return;
+  doorEl.style.transition = `transform ${DOOR_ANIMATION_DURATION}ms ease-in-out`;
+  doorEl.style.transformOrigin = 'left center';
+  doorEl.style.willChange = 'transform';
+  if (open) {
+    doorEl.style.transform = 'rotateY(90deg)';
+  } else {
+    doorEl.style.transform = 'rotateY(0deg)';
+  }
+  await wait(DOOR_ANIMATION_DURATION);
+}
+
+/**
+ * Fade out the current room container.
+ * @param {HTMLElement} container
+ * @returns {Promise<void>}
+ */
+export async function fadeOutRoom(container) {
+  if (!container) return;
+  container.style.transition = `opacity ${ROOM_FADE_DURATION}ms ease`;
+  container.style.opacity = '0';
+  await wait(ROOM_FADE_DURATION);
+}
+
+/**
+ * Fade in the new room container.
+ * @param {HTMLElement} container
+ * @returns {Promise<void>}
+ */
+export async function fadeInRoom(container) {
+  if (!container) return;
+  container.style.opacity = '0';
+  container.style.transition = `opacity ${ROOM_FADE_DURATION}ms ease`;
+  // Force reflow to apply initial opacity
+  void container.offsetWidth;
+  container.style.opacity = '1';
+  await wait(ROOM_FADE_DURATION);
+}
+
+/**
+ * Connect corridor tiles visually between rooms.
+ * This function adds a CSS class to corridor tiles connecting the two rooms.
+ * @param {HTMLElement[]} corridorTiles
+ */
+export function connectCorridors(corridorTiles) {
+  corridorTiles.forEach(tile => {
+    tile.classList.add('connected-corridor');
+  });
+}
+
+/**
+ * Perform a smooth transition between rooms.
+ * @param {HTMLElement} currentRoomEl - Current room container element.
+ * @param {HTMLElement} nextRoomEl - Next room container element.
+ * @param {HTMLElement[]} doors - Door elements between rooms.
+ * @param {HTMLElement[]} corridorTiles - Corridor tile elements connecting rooms.
+ */
+export async function transitionRooms(currentRoomEl, nextRoomEl, doors, corridorTiles) {
+  // Open doors
+  await Promise.all(doors.map(door => animateDoor(door, true)));
+  // Fade out current room
+  await fadeOutRoom(currentRoomEl);
+  // Close doors
+  await Promise.all(doors.map(door => animateDoor(door, false)));
+  // Connect corridors visually
+  connectCorridors(corridorTiles);
+  // Show next room and fade in
+  nextRoomEl.style.opacity = '0';
+  nextRoomEl.style.display = 'block';
+  await fadeInRoom(nextRoomEl);
+  // Hide previous room
+  currentRoomEl.style.display = 'none';
+}
